import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';

const AdminPage = () => {
  const navigate = useNavigate();

  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [comments, setComments] = useState([]);
  const [messages, setMessages] = useState([]);

  const [tab, setTab] = useState('users');

  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('all');
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 5;

  // ================= FETCH DATA =================
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [u, p, c, m] = await Promise.all([
          API.get('/admin/users'),
          API.get('/admin/posts'),
          API.get('/admin/comments'),
          API.get('/admin/messages')
        ]);

        setUsers(u.data || []);
        setPosts(p.data || []);
        setComments(c.data || []);
        setMessages(m.data || []);
      } catch (err) {
        console.error(err);
        alert("Error loading admin data");
      }
    };

    fetchData();
  }, []);

  // Reset page when controls change
  useEffect(() => {
    setCurrentPage(1);
  }, [tab, search, filter]);

  // ================= USER =================
  const toggleStatus = async (id) => {
    try {
      const { data } = await API.put(`/admin/users/${id}/status`);
      setUsers(prev =>
        prev.map(u => (u._id === id ? (data.user || data) : u))
      );
    } catch {
      alert("Error updating user");
    }
  };

  // ================= POSTS =================
  const removePost = async (id) => {
    if (!window.confirm("Delete post?")) return;
    await API.delete(`/posts/${id}`);
    setPosts(prev => prev.filter(p => p._id !== id));
  };

  const viewPost = (id) => navigate(`/posts/${id}`);

  // ================= COMMENTS =================
  const deleteComment = async (id) => {
    await API.delete(`/comments/${id}`);
    setComments(prev => prev.filter(c => c._id !== id));
  };

  // ================= MESSAGES =================
  const markAsRead = async (id) => {
    const { data } = await API.put(`/admin/messages/${id}/read`);
    setMessages(prev =>
      prev.map(m => (m._id === id ? (data.message || data) : m))
    );
  };

  const deleteMessage = async (id) => {
    await API.delete(`/admin/messages/${id}`);
    setMessages(prev => prev.filter(m => m._id !== id));
  };

  // ================= FILTER + SEARCH =================
  const getFilteredData = () => {
    let data = [];

    if (tab === 'users') data = users;
    if (tab === 'posts') data = posts;
    if (tab === 'comments') data = comments;
    if (tab === 'messages') data = messages;

    // 🔍 SAFE SEARCH
    data = data.filter(item => {
      try {
        const text = JSON.stringify(item || {}).toLowerCase();
        return text.includes(search.toLowerCase());
      } catch {
        return false;
      }
    });

    // 🎯 SAFE FILTER
    if (filter !== 'all') {
      data = data.filter(item =>
        String(item?.status || '').toLowerCase() === filter
      );
    }

    return data;
  };

  const filteredData = getFilteredData();

  // ================= PAGINATION =================
  const totalPages = Math.max(1, Math.ceil(filteredData.length / itemsPerPage));

  // ✅ FIX: prevent page overflow
  useEffect(() => {
    if (currentPage > totalPages) {
      setCurrentPage(1);
    }
  }, [filteredData, totalPages]);

  const paginatedData = filteredData.slice(
    (currentPage - 1) * itemsPerPage,
    currentPage * itemsPerPage
  );

  // ================= UI =================
  return (
    <div style={{ padding: 20 }}>
      <h2>Admin Panel</h2>

      {/* TABS */}
      <div style={{ display: 'flex', gap: 10 }}>
        {['users', 'posts', 'comments', 'messages'].map(t => (
          <button key={t} onClick={() => setTab(t)}>
            {t.toUpperCase()}
          </button>
        ))}
      </div>

      {/* SEARCH + FILTER */}
      <div style={{ marginTop: 20 }}>
        <input
          placeholder="Search..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />

        <select value={filter} onChange={e => setFilter(e.target.value)}>
          <option value="all">All</option>
          <option value="active">Active</option>
          <option value="inactive">Inactive</option>
          <option value="new">New</option>
          <option value="read">Read</option>
        </select>
      </div>

      {/* TABLE */}
      <table border="1" cellPadding="10" style={{ marginTop: 20, width: '100%' }}>
        <thead>
          <tr>
            {tab === 'users' && <>
              <th>Name</th><th>Email</th><th>Status</th><th>Action</th>
            </>}
            {tab === 'posts' && <>
              <th>Title</th><th>Action</th>
            </>}
            {tab === 'comments' && <>
              <th>Comment</th><th>Action</th>
            </>}
            {tab === 'messages' && <>
              <th>Message</th><th>Status</th><th>Action</th>
            </>}
          </tr>
        </thead>

        <tbody>
          {paginatedData.length === 0 && (
            <tr>
              <td colSpan="5" align="center">No data found</td>
            </tr>
          )}

          {paginatedData.map(item => (
            <tr key={item._id}>
              
              {/* USERS */}
              {tab === 'users' && <>
                <td>{item?.name || 'N/A'}</td>
                <td>{item?.email || 'N/A'}</td>
                <td>{String(item?.status || 'N/A').toUpperCase()}</td>
                <td>
                  <button onClick={() => toggleStatus(item._id)}>
                    Toggle
                  </button>
                </td>
              </>}

              {/* POSTS */}
              {tab === 'posts' && <>
                <td>{item?.title || 'N/A'}</td>
                <td>
                  <button onClick={() => viewPost(item._id)}>View</button>
                  <button onClick={() => removePost(item._id)}>Delete</button>
                </td>
              </>}

              {/* COMMENTS */}
              {tab === 'comments' && <>
                <td>{item?.body || 'N/A'}</td>
                <td>
                  <button onClick={() => deleteComment(item._id)}>Delete</button>
                </td>
              </>}

              {/* MESSAGES */}
              {tab === 'messages' && <>
                <td>{item?.body || item?.message || item?.content || 'N/A'}</td>
                <td>{String(item?.status || 'N/A').toUpperCase()}</td>
                <td>
                  {['new', 'unread', ''].includes(
                    String(item?.status || '').toLowerCase()
                  ) && (
                    <button onClick={() => markAsRead(item._id)}>
                      Mark Read
                    </button>
                  )}
                  <button onClick={() => deleteMessage(item._id)}>
                    Delete
                  </button>
                </td>
              </>}
            </tr>
          ))}
        </tbody>
      </table>

      {/* PAGINATION */}
      <div style={{ marginTop: 20 }}>
        <button
          disabled={currentPage === 1}
          onClick={() => setCurrentPage(p => p - 1)}
        >
          Prev
        </button>

        <span style={{ margin: '0 10px' }}>
          Page {currentPage} / {totalPages}
        </span>

        <button
          disabled={currentPage === totalPages}
          onClick={() => setCurrentPage(p => p + 1)}
        >
          Next
        </button>
      </div>
    </div>
  );
};

export default AdminPage;
